import React, { useEffect, useRef, useState } from 'react';
import { Stage, Layer, Group, Image as KonvaImage, Line, Circle } from 'react-konva';
import './SegmentationCanvas.css';

function flattenPoints(pts) {
    return pts.flatMap(p => [p.x, p.y]);
}

export default function SegmentationCanvas({
    fileUrl,
    annotations,
    onAnnotationsChange,
    scale,
    onWheelZoom,
    activeLabelColor,
    labelClasses,
    segmentationType,
    panopticOption,
    activeLabel,
    onFinishShape
}) {
    const stageRef = useRef(null);
    const containerRef = useRef(null);
    const [dims, setDims] = useState({ width: 0, height: 0 });
    const [konvaImg, setKonvaImg] = useState(null);

    // States for in-progress segmentation polygons
    const [tempInstancePoints, setTempInstancePoints] = useState([]);
    const [drawingInstancePolygon, setDrawingInstancePolygon] = useState(false);
    const [tempSemanticPoints, setTempSemanticPoints] = useState([]);
    const [drawingSemanticPolygon, setDrawingSemanticPolygon] = useState(false);

    useEffect(() => {
        const handleResize = () => {
            if (containerRef.current) {
                setDims({
                    width: containerRef.current.offsetWidth,
                    height: containerRef.current.offsetHeight,
                });
            }
        };
        window.addEventListener('resize', handleResize);
        handleResize();
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    useEffect(() => {
        if (!fileUrl) return;
        const img = new window.Image();
        img.src = fileUrl;
        img.onload = () => setKonvaImg(img);
        img.onerror = () => console.error('Could not load image:', fileUrl);
    }, [fileUrl]);

    function getRelativePointerPosition(evt) {
        const stage = stageRef.current;
        return stage ? stage.getPointerPosition() : null;
    }

    function addInstancePolygonPoint(pos) {
        setTempInstancePoints(prev => [...prev, pos]);
        setDrawingInstancePolygon(true);
    }

    function finalizeInstancePolygon() {
        if (tempInstancePoints.length >= 3) {
            const newAnn = {
                type: 'polygon',
                points: tempInstancePoints,
                label: activeLabel,
                color: activeLabelColor,
            };
            onAnnotationsChange([...annotations, newAnn]);
        }
        setTempInstancePoints([]);
        setDrawingInstancePolygon(false);
        onFinishShape && onFinishShape();
    }

    function addSemanticPolygonPoint(pos) {
        setTempSemanticPoints(prev => [...prev, pos]);
        setDrawingSemanticPolygon(true);
    }

    function finalizeSemanticPolygon() {
        if (tempSemanticPoints.length >= 3) {
            const newAnn = {
                type: 'polygon',
                points: tempSemanticPoints,
                label: activeLabel,
                color: activeLabelColor,
            };
            onAnnotationsChange([...annotations, newAnn]);
        }
        setTempSemanticPoints([]);
        setDrawingSemanticPolygon(false);
        onFinishShape && onFinishShape();
    }

    function handleMouseDown(evt) {
        const pos = getRelativePointerPosition(evt);
        if (!pos) return;
        if (segmentationType === 'instance') {
            addInstancePolygonPoint(pos);
        } else if (segmentationType === 'semantic') {
            addSemanticPolygonPoint(pos);
        } else if (segmentationType === 'panoptic') {
            if (panopticOption === 'instance') {
                addInstancePolygonPoint(pos);
            } else if (panopticOption === 'semantic') {
                addSemanticPolygonPoint(pos);
            }
        }
    }

    function handleDblClick() {
        if (segmentationType === 'instance') {
            if (drawingInstancePolygon) finalizeInstancePolygon();
        } else if (segmentationType === 'semantic') {
            if (drawingSemanticPolygon) finalizeSemanticPolygon();
        } else if (segmentationType === 'panoptic') {
            if (panopticOption === 'instance' && drawingInstancePolygon) {
                finalizeInstancePolygon();
            } else if (panopticOption === 'semantic' && drawingSemanticPolygon) {
                finalizeSemanticPolygon();
            }
        }
    }

    function handleWheel(evt) {
        evt.evt.preventDefault();
        onWheelZoom(evt.evt.deltaY);
    }

    return (
        <div className="canvas-container" ref={containerRef}>
            <Stage
                ref={stageRef}
                width={dims.width}
                height={dims.height}
                scaleX={scale}
                scaleY={scale}
                style={{ background: '#dfe6e9' }}
                onWheel={handleWheel}
                onMouseDown={handleMouseDown}
                onDblClick={handleDblClick}
            >
                <Layer>
                    <Group>
                        {konvaImg && (
                            <KonvaImage image={konvaImg} width={konvaImg.width} height={konvaImg.height} />
                        )}
                        {/* Render completed segmentation annotations */}
                        {annotations.map((ann, i) => {
                            if (ann.type === 'polygon') {
                                const pts = flattenPoints(ann.points);
                                return (
                                    <Line
                                        key={i}
                                        points={pts}
                                        fill={activeLabelColor + '55'}
                                        stroke={activeLabelColor}
                                        strokeWidth={2 / scale}
                                        closed
                                    />
                                );
                            }
                            return null;
                        })}
                        {/* Render in-progress instance segmentation polygon */}
                        {(drawingInstancePolygon &&
                            (segmentationType === 'instance' ||
                                (segmentationType === 'panoptic' && panopticOption === 'instance'))) && (
                                <>
                                    {tempInstancePoints.length > 1 && (
                                        <Line
                                            points={flattenPoints([...tempInstancePoints, tempInstancePoints[0]])}
                                            fill={activeLabelColor + '55'}
                                            stroke={activeLabelColor}
                                            strokeWidth={2 / scale}
                                            closed
                                        />
                                    )}
                                    {tempInstancePoints.map((pt, idx) => (
                                        <Circle
                                            key={idx}
                                            x={pt.x}
                                            y={pt.y}
                                            radius={4 / scale}
                                            fill="#fff"
                                            stroke={activeLabelColor}
                                            strokeWidth={1 / scale}
                                        />
                                    ))}
                                </>
                            )}
                        {/* Render in-progress semantic segmentation polygon */}
                        {(drawingSemanticPolygon &&
                            (segmentationType === 'semantic' ||
                                (segmentationType === 'panoptic' && panopticOption === 'semantic'))) && (
                                <>
                                    {tempSemanticPoints.length > 1 && (
                                        <Line
                                            points={flattenPoints([...tempSemanticPoints, tempSemanticPoints[0]])}
                                            fill={activeLabelColor + '55'}
                                            stroke={activeLabelColor}
                                            strokeWidth={2 / scale}
                                            closed
                                        />
                                    )}
                                    {tempSemanticPoints.map((pt, idx) => (
                                        <Circle
                                            key={idx}
                                            x={pt.x}
                                            y={pt.y}
                                            radius={4 / scale}
                                            fill="#fff"
                                            stroke={activeLabelColor}
                                            strokeWidth={1 / scale}
                                        />
                                    ))}
                                </>
                            )}
                    </Group>
                </Layer>
            </Stage>
        </div>
    );
}
